-- CCN Council Prep Pro — practice question batch 3
-- 193 AI-generated labeled practice questions filling curriculum gaps
-- (Radiology, ICT/Nursing Informatics, Pharmacology, Ethico-Legal, Management/Teaching,
-- Disaster & Emergency Nursing, Laboratory Sciences). source='AI Practice Question' on every row.
-- Run this once in the Supabase SQL Editor (Project -> SQL Editor -> New query).

on conflict (id) do update set topic=excluded.topic, source=excluded.source, q=excluded.q, opts=excluded.opts, ans_idx=excluded.ans_idx, exp=excluded.exp, category=excluded.category, category_icon=excluded.category_icon, is_active=true;