insert into public.questions (id, topic, source, q, opts, ans_idx, exp, category, category_icon, is_active)
values
(3015, 'Radiology (CCN 427)', 'AI Practice Question', 'Ionic (High Osmolar) contrast media, compared to non-ionic (Low Osmolar) contrast media, are associated with:', '["Fewer side effects and higher cost", "More side effects but lower cost", "Identical side-effect profile and cost", "No side effects at any dose"]'::jsonb, 1, 'Ionic/HOCM agents dissociate into ions, have high osmolality, and cause more reactions, but are cheaper than non-ionic/LOCM agents such as iohexol.', 'Radiology & Imaging', '🩻', true),
(3016, 'Radiology (CCN 427)', 'AI Practice Question', 'Which contrast media type is preferred in high-risk patients such as those with renal failure, cardiac failure, or diabetes mellitus?', '["Ionic (High Osmolar) contrast media", "Non-ionic (Low Osmolar) contrast media", "Barium sulfate only", "No contrast is ever needed in high-risk patients"]'::jsonb, 1, 'Non-ionic/Low Osmolar Contrast Media (LOCM) cause fewer reactions and are preferred in high-risk groups including renal failure, cardiac failure, diabetes, sickle cell disease and the elderly.', 'Radiology & Imaging', '🩻', true),
(3017, 'Radiology (CCN 427)', 'AI Practice Question', 'Barium contrast studies are absolutely contraindicated when there is suspicion of:', '["Simple constipation", "Bowel perforation", "Mild gastritis", "Uncomplicated reflux"]'::jsonb, 1, 'Barium leaking into the peritoneum through a perforation causes barium peritonitis and adhesions, which is life-threatening — water-soluble contrast is used instead if perforation is suspected.', 'Radiology & Imaging', '🩻', true),
(3018, 'Radiology (CCN 427)', 'AI Practice Question', 'Before administering iodinated contrast, the standard test dose protocol is to give:', '["The full dose immediately with no test", "1ml, then wait 5 minutes before proceeding", "10ml, then wait 30 minutes", "A test dose only in children"]'::jsonb, 1, 'A 1ml test dose is given, followed by a 5-minute wait to observe for an early reaction, before proceeding with the full contrast dose.', 'Radiology & Imaging', '🩻', true),
(3019, 'Radiology (CCN 427)', 'AI Practice Question', 'A patient with a documented previous reaction to contrast media requiring a repeat contrast-enhanced scan should receive:', '["No premedication is ever required", "Steroid prophylaxis (e.g. prednisolone) before the procedure, plus IV hydrocortisone before injection", "Only a larger dose of the same contrast agent", "Antibiotics prior to the scan"]'::jsonb, 1, 'Standard prophylaxis for a patient with a prior contrast reaction includes oral steroid cover (e.g. prednisolone 50mg every 6h for 24h before and 12h after) plus IV hydrocortisone immediately before the injection.', 'Radiology & Imaging', '🩻', true),
(3020, 'Radiology (CCN 427)', 'AI Practice Question', 'On chest X-ray, air bronchograms are a classic radiographic sign of:', '["Pneumothorax", "Consolidation (e.g. pneumonia)", "Pleural effusion", "Rib fracture"]'::jsonb, 1, 'Air bronchograms — air-filled bronchi visible against surrounding opacified alveoli — are a hallmark of consolidation.', 'Radiology & Imaging', '🩻', true),
(3021, 'Radiology (CCN 427)', 'AI Practice Question', 'A widened mediastinum on chest X-ray following trauma should raise urgent suspicion of:', '["Simple rib fracture", "Aortic disruption/traumatic aortic injury", "Uncomplicated bronchitis", "Chronic COPD"]'::jsonb, 1, 'A widened mediastinum after trauma is a key radiographic red flag for aortic disruption and requires urgent further imaging (e.g. CT angiogram).', 'Radiology & Imaging', '🩻', true),
(3022, 'Radiology (CCN 427)', 'AI Practice Question', 'A pleural effusion typically becomes visible on a standard chest X-ray only once fluid volume reaches approximately:', '["5–10ml", "150–300ml", "2–3 litres", "There is no minimum volume — any amount is visible"]'::jsonb, 1, 'A pleural effusion generally needs to reach roughly 150–300ml before it becomes detectable on a standard chest X-ray.', 'Radiology & Imaging', '🩻', true),
(3023, 'Radiology (CCN 427)', 'AI Practice Question', 'The mnemonic ''IPPR'' used to systematically check a chest X-ray before interpretation stands for:', '["Inspiration, Position, Penetration, Rotation", "Infection, Pneumonia, Pleura, Ribs", "Intubation, Perfusion, Pressure, Recovery", "Imaging, Patient, Protocol, Report"]'::jsonb, 0, 'IPPR is the standard systematic check before reading a chest X-ray: adequate Inspiration, correct Position, correct Penetration (exposure), and no Rotation.', 'Radiology & Imaging', '🩻', true),
(3024, 'Radiology (CCN 427)', 'AI Practice Question', 'Which of the following is classified as a positive (radio-opaque/white-appearing) contrast agent?', '["Room air", "Carbon dioxide", "Barium", "Vacuum/no contrast"]'::jsonb, 2, 'Positive contrast agents such as iodine-based media and barium are dense and appear white/opaque on imaging, unlike negative agents such as air or CO2 which appear dark/lucent.', 'Radiology & Imaging', '🩻', true),
(3025, 'Radiology (CCN 427)', 'AI Practice Question', 'Negative contrast agents (e.g. air, carbon dioxide) appear on imaging as:', '["Dense and white (opaque)", "Dark and lucent", "Identical in appearance to iodinated contrast", "Only visible on MRI, never on X-ray"]'::jsonb, 1, 'Negative contrast agents such as air or CO2 have low density and appear dark/lucent on radiographic images, the opposite of positive agents like barium or iodine.', 'Radiology & Imaging', '🩻', true),
(3026, 'Radiology (CCN 427)', 'AI Practice Question', 'Severe/major reactions to contrast media can include all of the following EXCEPT:', '["Laryngeal oedema", "Cardiac arrhythmia", "Respiratory arrest", "Improved renal perfusion"]'::jsonb, 3, 'Major contrast reactions include laryngeal oedema, pulmonary oedema, respiratory arrest, cardiac arrhythmia, coma and death — contrast does not improve renal perfusion, and can in fact cause contrast-induced nephropathy.', 'Radiology & Imaging', '🩻', true),
(3027, 'Radiology (CCN 427)', 'AI Practice Question', 'On a plain abdominal X-ray, multiple dilated bowel loops with air-fluid levels on an erect film are classic findings of:', '["Normal bowel gas pattern", "Intestinal obstruction", "Chronic constipation only", "Gallstones"]'::jsonb, 1, 'Dilated, gas-filled bowel loops with air-fluid levels on an erect film are the classic radiographic sign of mechanical bowel obstruction.', 'Radiology & Imaging', '🩻', true),
(3028, 'Radiology (CCN 427)', 'AI Practice Question', 'Free air visible under the diaphragm on an erect chest/abdominal X-ray most strongly suggests:', '["Normal post-prandial bowel gas", "Perforation of a hollow viscus", "Pulmonary embolism", "Chronic heart failure"]'::jsonb, 1, 'Pneumoperitoneum (free sub-diaphragmatic air) is a classic sign of a perforated hollow abdominal organ and represents a surgical emergency.', 'Radiology & Imaging', '🩻', true),
(3029, 'Radiology (CCN 427)', 'AI Practice Question', 'IVU (Intravenous Urogram) is a radiological investigation primarily used to assess:', '["The biliary tree", "The urinary tract (kidneys, ureters, bladder)", "The gastrointestinal tract", "The cerebral vasculature"]'::jsonb, 1, 'IVU uses IV contrast excreted by the kidneys to outline the urinary tract, demonstrating renal function and structural abnormalities.', 'Radiology & Imaging', '🩻', true),
(3030, 'Radiology (CCN 427)', 'AI Practice Question', 'A correctly positioned central venous catheter tip on chest X-ray should sit at or just above the:', '["Aortic arch", "Cavo-atrial junction (junction of SVC and right atrium)", "Left ventricle", "Pulmonary artery bifurcation"]'::jsonb, 1, 'The ideal CVC tip position is at or just above the junction of the superior vena cava and right atrium (the cavo-atrial junction), confirmed by chest X-ray after insertion.', 'Radiology & Imaging', '🩻', true),
(3031, 'Radiology (CCN 427)', 'AI Practice Question', 'An endotracheal tube tip on chest X-ray should ideally sit approximately how far above the carina?', '["At the level of the carina exactly", "3–5 cm above the carina", "10–12 cm above the carina", "In the right main bronchus"]'::jsonb, 1, 'The ETT tip should sit roughly 3–5 cm above the carina to avoid accidental right main bronchus intubation or extubation with neck movement.', 'Radiology & Imaging', '🩻', true),
(3032, 'Radiology (CCN 427)', 'AI Practice Question', 'Ultrasound is favoured over CT/X-ray for repeated bedside assessment in critical care mainly because it:', '["Uses ionising radiation for sharper detail", "Avoids ionising radiation and is portable for bedside use", "Always requires iodinated contrast", "Cannot assess fluid collections"]'::jsonb, 1, 'Ultrasound is radiation-free and portable, making it ideal for repeated bedside assessment (e.g. FAST scan, guiding line placement) in critically ill patients.', 'Radiology & Imaging', '🩻', true),
(3033, 'Radiology (CCN 427)', 'AI Practice Question', 'Which imaging modality is generally first-line for rapidly diagnosing acute intracranial haemorrhage?', '["Ultrasound", "CT scan", "Plain X-ray of the skull", "Doppler flow study"]'::jsonb, 1, 'CT scanning is fast and widely available, making it the first-line imaging choice for suspected acute intracranial haemorrhage.', 'Radiology & Imaging', '🩻', true),
(3034, 'Radiology (CCN 427)', 'AI Practice Question', 'MRI requires special screening before scanning mainly because of the risk to patients with:', '["Chronic headache", "Non-MRI-compatible metallic implants or pacemakers", "Mild anaemia", "Recent minor cold"]'::jsonb, 1, 'MRI''s strong magnetic field can dislodge or interfere with certain metallic implants and non-MRI-safe pacemakers, so screening is essential before scanning.', 'Radiology & Imaging', '🩻', true),
(3035, 'Radiology (CCN 427)', 'AI Practice Question', 'On the periodic table, which element used in contrast media has the highest atomic number of the three commonly referenced in radiology (iodine, barium, gadolinium)?', '["Iodine (53)", "Barium (56)", "Gadolinium (64)", "They are all equal"]'::jsonb, 2, 'Gadolinium has atomic number 64, higher than barium (56) and iodine (53) — gadolinium is used specifically for MRI contrast, not X-ray/CT.', 'Radiology & Imaging', '🩻', true),
(3036, 'Radiology (CCN 427)', 'AI Practice Question', 'Oral iodinated contrast carries a specific risk if aspirated, namely:', '["No risk at all — it is inert if aspirated", "Pulmonary oedema and chemical pneumonitis", "Immediate cardiac arrest", "Permanent loss of taste"]'::jsonb, 1, 'Aspiration of oral iodinated contrast can cause pulmonary oedema and chemical pneumonitis, which is why aspiration risk must be assessed before oral contrast is given.', 'Radiology & Imaging', '🩻', true),
(3037, 'Radiology (CCN 427)', 'AI Practice Question', 'A nasogastric tube''s position should be confirmed before feeding by:', '["Auscultation (''whoosh test'') alone", "pH testing of aspirate and/or X-ray confirmation", "The patient''s verbal comfort report only", "Tube colour"]'::jsonb, 1, 'Best practice for confirming NG tube position is pH testing of aspirate (ideally ≤5.5) and/or radiographic confirmation — auscultation alone is unreliable and is no longer recommended as a sole method.', 'Radiology & Imaging', '🩻', true),
(3038, 'Radiology (CCN 427)', 'AI Practice Question', 'A haemothorax and a pleural effusion from another cause are best distinguished by:', '["X-ray appearance alone — they look completely different", "Clinical history and pleural fluid analysis (thoracentesis), since both look similar radiographically", "CT scan is never useful for either", "They cannot be distinguished by any method"]'::jsonb, 1, 'Blood and other pleural fluids produce a similar meniscus/blunted costophrenic angle on X-ray, so differentiating haemothorax from another effusion relies on clinical context and pleural fluid analysis.', 'Radiology & Imaging', '🩻', true),
(3039, 'Radiology (CCN 427)', 'AI Practice Question', 'A key nursing responsibility regarding a patient''s radiological investigation is to:', '["Interpret the film independently and adjust treatment without medical input", "Ensure correct patient identification, positioning and safety precautions (e.g. contrast/allergy screening, shielding), and communicate relevant findings to the radiology team", "Perform imaging without a physician order", "Avoid documenting the investigation"]'::jsonb, 1, 'The nurse''s role centres on patient safety — correct ID/positioning, appropriate precautions, and clear communication with the radiology team — not independent image interpretation.', 'Radiology & Imaging', '🩻', true),
(3040, 'Nursing Informatics & ICT', 'AI Practice Question', 'The Central Processing Unit (CPU) of a computer is primarily responsible for:', '["Permanent data storage only", "Executing instructions and processing data", "Displaying output on the monitor only", "Providing internet connectivity only"]'::jsonb, 1, 'The CPU is the computer''s ''brain'' — it fetches, decodes and executes instructions, performing the actual data processing.', 'Nursing Informatics & ICT', '💻', true),
(3041, 'Nursing Informatics & ICT', 'AI Practice Question', 'Random Access Memory (RAM) differs from Read Only Memory (ROM) in that RAM is:', '["Permanent and non-volatile", "Volatile — its contents are lost when power is off", "Used only for long-term archival storage", "Not involved in program execution"]'::jsonb, 1, 'RAM is volatile working memory used for actively running programs and data; its contents are lost when the computer powers off, unlike ROM.', 'Nursing Informatics & ICT', '💻', true),
(3042, 'Nursing Informatics & ICT', 'AI Practice Question', 'Which of the following is an example of secondary (long-term) storage?', '["RAM", "Hard disk drive", "CPU cache", "CPU register"]'::jsonb, 1, 'Secondary storage devices such as hard disks, USB flash drives and optical disks retain data long-term, unlike RAM which is volatile working memory.', 'Nursing Informatics & ICT', '💻', true),
(3043, 'Nursing Informatics & ICT', 'AI Practice Question', 'System software, as distinct from application software, is best described as:', '["Software written by end users for a single specific task", "Software that manages computer hardware and provides a platform for other programs to run (e.g. an operating system)", "Software used exclusively for entertainment", "A type of computer virus"]'::jsonb, 1, 'System software (like an operating system) manages hardware resources and provides the platform on which application software runs.', 'Nursing Informatics & ICT', '💻', true),
(3044, 'Nursing Informatics & ICT', 'AI Practice Question', 'A hospital''s electronic health record (EHR) system is an example of a:', '["Nursing Information System / Hospital Information System", "Type of computer hardware only", "Antivirus programme", "Physical storage device"]'::jsonb, 0, 'An EHR is a software application within a Hospital/Nursing Information System, used to manage patient data electronically.', 'Nursing Informatics & ICT', '💻', true),
(3045, 'Nursing Informatics & ICT', 'AI Practice Question', 'One key benefit of computer-based patient records over paper records is:', '["They can never be accessed by unauthorised persons", "Improved legibility, faster retrieval, and easier data sharing across care providers", "They eliminate the need for any data backup", "They require no staff training to use"]'::jsonb, 1, 'Electronic records improve legibility and speed of retrieval and allow authorised providers to share information more efficiently than paper charts.', 'Nursing Informatics & ICT', '💻', true),
(3046, 'Nursing Informatics & ICT', 'AI Practice Question', 'Telemedicine refers to:', '["The use of telecommunications technology to deliver healthcare services remotely", "A type of medical imaging equipment", "A brand of hospital software only used for billing", "A paper-based referral system"]'::jsonb, 0, 'Telemedicine uses telecommunications (video calls, remote monitoring, etc.) to deliver clinical healthcare services when the provider and patient are not physically together.', 'Nursing Informatics & ICT', '💻', true),
(3047, 'Nursing Informatics & ICT', 'AI Practice Question', 'A cardiac monitor and pulse oximeter used in the ICU are examples of which category of electronic devices in healthcare?', '["Diagnostic devices", "Monitoring devices", "Treatment devices", "Storage devices"]'::jsonb, 1, 'Cardiac monitors and pulse oximeters continuously track a patient''s physiological status, placing them in the monitoring devices category.', 'Nursing Informatics & ICT', '💻', true),
(3048, 'Nursing Informatics & ICT', 'AI Practice Question', 'CT scan and ultrasound machines are best classified as which type of healthcare ICT device?', '["Diagnostic devices", "Monitoring devices only", "Treatment devices only", "Communication devices"]'::jsonb, 0, 'CT and ultrasound are used to establish or confirm a diagnosis by producing images of internal structures, making them diagnostic devices.', 'Nursing Informatics & ICT', '💻', true),
(3049, 'Nursing Informatics & ICT', 'AI Practice Question', 'Batch processing, as a method of file processing, is best described as:', '["Processing transactions immediately as they occur, one at a time", "Collecting and processing a group of transactions together at a scheduled time", "Processing that requires no computer at all", "A method used only for video files"]'::jsonb, 1, 'Batch processing accumulates data over a period and processes it together at a set time, rather than immediately as each transaction occurs.', 'Nursing Informatics & ICT', '💻', true),
(3050, 'Nursing Informatics & ICT', 'AI Practice Question', 'On-line (real-time) processing, compared to batch processing, is characterised by:', '["Data being processed immediately as it is entered, giving instant updates", "Data being stored for days before any processing occurs", "Only being usable for printed reports", "Requiring no network connection"]'::jsonb, 0, 'On-line/real-time processing updates records immediately as transactions occur, unlike batch processing which groups and delays processing.', 'Nursing Informatics & ICT', '💻', true),
(3051, 'Nursing Informatics & ICT', 'AI Practice Question', 'A master file in a computerised records system typically contains:', '["Temporary data deleted after each session", "Relatively permanent, core reference data about an entity (e.g. patient demographic records)", "Only system error logs", "Only images and video files"]'::jsonb, 1, 'Master files hold relatively stable, core data (such as patient demographics) that is referenced and updated over time, unlike temporary transaction files.', 'Nursing Informatics & ICT', '💻', true),
(3052, 'Nursing Informatics & ICT', 'AI Practice Question', 'Data standardization and classification in nursing informatics (e.g. using NANDA, NIC, NOC) primarily helps to:', '["Make nursing documentation ambiguous and inconsistent", "Enable consistent communication, data comparison and research across different settings", "Replace the need for any nursing assessment", "Increase paperwork with no benefit"]'::jsonb, 1, 'Standardised nursing languages/classifications allow consistent terminology, enabling comparison, communication and research across different institutions and systems.', 'Nursing Informatics & ICT', '💻', true),
(3053, 'Nursing Informatics & ICT', 'AI Practice Question', 'One major effect of ICT on the quality of nursing care is that it:', '["Has no measurable effect on patient safety", "Can improve patient safety through faster access to accurate information and decision support", "Always increases nursing workload with no benefit", "Eliminates the need for clinical judgement"]'::jsonb, 1, 'ICT tools (e-records, decision-support alerts, rapid data access) can improve patient safety and care quality by giving nurses faster access to accurate, organised information.', 'Nursing Informatics & ICT', '💻', true),
(3054, 'Nursing Informatics & ICT', 'AI Practice Question', 'USB flash drives and optical disks (CD/DVD) are examples of:', '["Primary memory (RAM)", "Secondary/portable storage devices", "Input devices only", "Output devices only"]'::jsonb, 1, 'USB flash drives and optical disks are portable secondary storage media used to store and transfer data outside the computer''s main memory.', 'Nursing Informatics & ICT', '💻', true),
(3055, 'Nursing Informatics & ICT', 'AI Practice Question', 'A Hospital Information System (HIS) is best defined as:', '["A single stand-alone computer used only by the IT department", "An integrated system that manages a hospital''s clinical, administrative and financial information", "A type of medical imaging machine", "A manual paper filing cabinet"]'::jsonb, 1, 'A HIS integrates clinical, administrative and financial data management across the hospital into one coordinated system.', 'Nursing Informatics & ICT', '💻', true),
(3056, 'Nursing Informatics & ICT', 'AI Practice Question', 'Protecting electronic access to client data primarily relies on which of the following measures?', '["Leaving all records openly accessible to any staff member for convenience", "User authentication (passwords/logins), access controls and audit trails", "Printing all records to avoid computer use entirely", "Disabling all data backups"]'::jsonb, 1, 'Controlled access via authentication, role-based permissions and audit trails is a core safeguard for protecting confidential electronic client data.', 'Nursing Informatics & ICT', '💻', true),
(3057, 'Nursing Informatics & ICT', 'AI Practice Question', 'Computer networking in a hospital setting primarily enables:', '["Sharing of data and resources between multiple connected computers/devices", "Only playing multimedia content", "Complete isolation of every department''s data", "Slower access to patient information"]'::jsonb, 0, 'Networking connects computers and devices so that data, applications and resources (such as a shared EHR) can be accessed and shared across departments.', 'Nursing Informatics & ICT', '💻', true),
(3058, 'Nursing Informatics & ICT', 'AI Practice Question', 'Which of the following best describes ''utility software''?', '["Software designed to perform maintenance tasks such as antivirus scanning or disk cleanup", "Software used only to write documents", "A type of physical computer hardware", "A programming language"]'::jsonb, 0, 'Utility software performs system maintenance and support tasks (e.g. antivirus, disk cleanup, backup tools) rather than being an end-user application.', 'Nursing Informatics & ICT', '💻', true),
(3059, 'Nursing Informatics & ICT', 'AI Practice Question', 'Application software, as opposed to system software, is best exemplified by:', '["The computer''s operating system", "A word processing or spreadsheet programme used by an end user", "The computer''s BIOS/firmware", "Device drivers"]'::jsonb, 1, 'Application software (like word processors or an EHR charting application) is designed for end users to perform specific tasks, unlike system software which manages the hardware itself.', 'Nursing Informatics & ICT', '💻', true),
(3060, 'Nursing Informatics & ICT', 'AI Practice Question', 'Index-sequential file organisation allows records to be accessed:', '["Only in the exact order they were originally entered, with no shortcuts", "Both sequentially and directly via an index, combining the benefits of both methods", "Only by physically searching every record one by one with no index", "Never — it is a theoretical method with no real use"]'::jsonb, 1, 'Index-sequential organisation maintains an index that allows direct access to specific records while still supporting sequential processing.', 'Nursing Informatics & ICT', '💻', true),
(3061, 'Nursing Informatics & ICT', 'AI Practice Question', 'Multi-user processing in a hospital computer system allows:', '["Only one staff member to use the system at any given time", "Multiple users to access and use the system concurrently", "Only administrators to log in", "No simultaneous data entry by different departments"]'::jsonb, 1, 'Multi-user systems are designed so several staff members across departments can access and use the system at the same time.', 'Nursing Informatics & ICT', '💻', true),
(3062, 'Nursing Informatics & ICT', 'AI Practice Question', 'Nursing Information System Management primarily focuses on:', '["Managing data specific to nursing practice, such as care plans, assessments and nursing documentation", "Only managing the hospital''s financial billing", "Only managing the pharmacy stock levels", "Managing building maintenance requests"]'::jsonb, 0, 'Nursing Information Systems are designed to support nursing-specific data needs — care planning, documentation, assessments and outcomes tracking.', 'Nursing Informatics & ICT', '💻', true),
(3063, 'Nursing Informatics & ICT', 'AI Practice Question', 'A key consideration when using electronic/digital devices for patient monitoring in critical care is:', '["Regular calibration, maintenance and staff competency in device use", "That devices never need calibration once installed", "That any staff member can operate any device without training", "That documentation of device readings is unnecessary"]'::jsonb, 0, 'Accurate monitoring depends on properly calibrated, well-maintained equipment and staff who are competent and trained in its correct use.', 'Nursing Informatics & ICT', '💻', true),
(3064, 'Nursing Informatics & ICT', 'AI Practice Question', 'Which of the following best describes the internet''s role in critical care nursing practice today?', '["It has no legitimate clinical use", "It supports access to research literature, telemedicine, and remote consultation/education", "It is used only for personal entertainment during shifts", "It replaces the need for clinical assessment skills"]'::jsonb, 1, 'The internet supports evidence-based practice, telemedicine consultations, remote specialist input and ongoing professional education in critical care nursing.', 'Nursing Informatics & ICT', '💻', true),
(3065, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'During adult cardiac arrest, IV adrenaline (epinephrine) is administered at what dose and interval?', '["0.1mg every 1 minute", "1mg every 3–5 minutes", "10mg once only", "1mg every 15 minutes"]'::jsonb, 1, 'Standard ACLS dosing is 1mg IV adrenaline every 3–5 minutes during cardiac arrest resuscitation.', 'ICU Pharmacology', '💊', true),
(3066, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'Amiodarone is primarily indicated in cardiac arrest management for:', '["Asystole only", "Shockable rhythms (VF/pulseless VT) refractory to defibrillation", "Bradycardia", "Hypertensive emergency"]'::jsonb, 1, 'Amiodarone is used for ventricular fibrillation or pulseless ventricular tachycardia that persists despite defibrillation attempts.', 'ICU Pharmacology', '💊', true),
(3067, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'In septic shock, which vasopressor is generally recommended as first-line?', '["Dobutamine", "Noradrenaline (norepinephrine)", "Salbutamol", "Furosemide"]'::jsonb, 1, 'Noradrenaline is the first-line vasopressor recommended in septic shock guidelines to restore adequate mean arterial pressure.', 'ICU Pharmacology', '💊', true),
(3068, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'Dobutamine is primarily classified as a(n):', '["Pure vasoconstrictor with no inotropic effect", "Inotrope, mainly used to improve cardiac output in cardiogenic shock", "Anticoagulant", "Bronchodilator"]'::jsonb, 1, 'Dobutamine is a beta-1 agonist inotrope that increases cardiac contractility and output, commonly used in cardiogenic shock/low cardiac output states.', 'ICU Pharmacology', '💊', true),
(3069, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'Neuromuscular blocking agents (e.g. vecuronium) must always be administered together with:', '["Nothing else is required", "Adequate sedation and analgesia, since paralytics do not sedate or relieve pain", "A diuretic", "An antihistamine"]'::jsonb, 1, 'Neuromuscular blockers paralyse muscles but provide no sedation or analgesia — a paralysed, unsedated patient would be conscious and in pain but unable to communicate, which is why adequate sedation/analgesia must always accompany their use.', 'ICU Pharmacology', '💊', true),
(3070, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'When titrating sedation in a mechanically ventilated ICU patient, the nurse should primarily use:', '["The patient''s family''s preference alone", "A validated sedation scale (e.g. RASS) to guide titration", "No formal scale — sedation should be maximised at all times", "Blood pressure alone as the only guide"]'::jsonb, 1, 'Validated sedation scales such as the Richmond Agitation-Sedation Scale (RASS) guide safe titration, avoiding both under- and over-sedation.', 'ICU Pharmacology', '💊', true),
(3071, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'Salbutamol relieves bronchospasm mainly by acting as a:', '["Beta-2 adrenergic agonist causing bronchial smooth muscle relaxation", "Anticholinergic that dries secretions", "Corticosteroid reducing inflammation only", "Mucolytic that thins mucus"]'::jsonb, 0, 'Salbutamol is a beta-2 agonist that relaxes bronchial smooth muscle, producing rapid bronchodilation.', 'ICU Pharmacology', '💊', true),
(3072, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'Ipratropium bromide, used for bronchospasm, works through which mechanism?', '["Beta-2 agonism", "Anticholinergic action, blocking bronchoconstriction mediated by acetylcholine", "Direct mast cell stabilisation", "Antihistamine action"]'::jsonb, 1, 'Ipratropium is an anticholinergic bronchodilator that blocks acetylcholine-mediated bronchoconstriction, complementing beta-2 agonists like salbutamol.', 'ICU Pharmacology', '💊', true),
(3073, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'The specific antidote for opioid overdose (e.g. morphine, fentanyl) is:', '["Flumazenil", "Naloxone", "N-acetylcysteine", "Activated charcoal"]'::jsonb, 1, 'Naloxone is a competitive opioid receptor antagonist used to reverse opioid-induced respiratory depression.', 'ICU Pharmacology', '💊', true),
(3074, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'The specific antidote for benzodiazepine overdose is:', '["Naloxone", "Flumazenil", "Protamine sulfate", "Dantrolene"]'::jsonb, 1, 'Flumazenil is a competitive benzodiazepine receptor antagonist used to reverse benzodiazepine sedation/overdose.', 'ICU Pharmacology', '💊', true),
(3075, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'N-acetylcysteine is the specific antidote for overdose of which drug?', '["Paracetamol (acetaminophen)", "Warfarin", "Digoxin", "Aspirin"]'::jsonb, 0, 'N-acetylcysteine replenishes glutathione stores and prevents hepatotoxicity from paracetamol overdose.', 'ICU Pharmacology', '💊', true),
(3076, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'Activated charcoal is most effective in acute poisoning management when given:', '["More than 24 hours after ingestion", "Early after ingestion (typically within about 1 hour)", "Only intravenously", "Only for iron overdose"]'::jsonb, 1, 'Activated charcoal binds many oral toxins in the gut and is most effective when given soon after ingestion, typically within about an hour.', 'ICU Pharmacology', '💊', true),
(3077, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'Protamine sulfate is used to reverse the anticoagulant effect of:', '["Warfarin", "Heparin", "Aspirin", "Clopidogrel"]'::jsonb, 1, 'Protamine sulfate binds and neutralises heparin, reversing its anticoagulant effect.', 'ICU Pharmacology', '💊', true),
(3078, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'Vitamin K is used to reverse excessive anticoagulation from which drug?', '["Heparin", "Warfarin", "Enoxaparin", "Aspirin"]'::jsonb, 1, 'Vitamin K restores synthesis of clotting factors suppressed by warfarin, reversing its anticoagulant effect (though onset is slower than with prothrombin complex concentrate).', 'ICU Pharmacology', '💊', true),
(3079, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'Before administering any weight-based critical care drug infusion, best practice is to:', '["Skip verification if the nurse is experienced", "Have the calculation independently double-checked by a second nurse/pharmacist", "Round the dose up for safety margin", "Administer without checking the infusion pump rate"]'::jsonb, 1, 'Independent double-checking of weight-based dose and infusion pump rate calculations is a core medication-safety practice in critical care.', 'ICU Pharmacology', '💊', true),
(3080, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'Antibiotic therapy in a critically ill septic patient should ideally begin:', '["Only after all culture results are back, even if this takes days", "Empirically as soon as possible after cultures are drawn, then narrowed once sensitivities return", "Never before a specialist consult, regardless of severity", "Only if the patient requests it"]'::jsonb, 1, 'In sepsis, empiric broad-spectrum antibiotics should be started promptly after cultures are obtained, then de-escalated/narrowed once culture and sensitivity results are available.', 'ICU Pharmacology', '💊', true),
(3081, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'Mucolytic agents such as acetylcysteine work by:', '["Constricting the airways", "Breaking down disulfide bonds in mucus to thin secretions", "Increasing mucus production", "Sedating the respiratory centre"]'::jsonb, 1, 'Mucolytics like acetylcysteine break disulfide bonds within mucus glycoproteins, reducing its viscosity so it can be cleared more easily.', 'ICU Pharmacology', '💊', true),
(3082, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'Hydrocortisone, used as an adjunct in some cases of septic shock, is a:', '["Bronchodilator", "Corticosteroid with anti-inflammatory and mineralocorticoid effects", "Neuromuscular blocker", "Vasopressor"]'::jsonb, 1, 'Hydrocortisone is a corticosteroid sometimes used as an adjunct in septic shock refractory to fluids and vasopressors, providing anti-inflammatory and mineralocorticoid effects.', 'ICU Pharmacology', '💊', true),
(3083, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'Propofol, commonly used for ICU sedation, is characterised by:', '["A slow onset and prolonged, unpredictable duration of action", "A rapid onset and relatively rapid offset, allowing quick titration and neurological assessment", "No effect on blood pressure", "Being an opioid analgesic"]'::jsonb, 1, 'Propofol''s rapid onset and offset make it useful for titratable sedation and allow periodic neurological assessment, though it can cause hypotension.', 'ICU Pharmacology', '💊', true),
(3084, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'A key nursing precaution when administering IV potassium chloride is to:', '["Give it as a rapid IV push for fast correction", "Never give it as an undiluted rapid IV push, due to risk of fatal arrhythmia", "Administer it intramuscularly for safety", "Mix it with any other IV drug freely"]'::jsonb, 1, 'Undiluted or rapidly pushed IV potassium can cause fatal cardiac arrhythmias — it must always be diluted and infused slowly, usually via an infusion pump with cardiac monitoring.', 'ICU Pharmacology', '💊', true),
(3085, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'Anxiolytic drugs such as benzodiazepines are primarily used in critical care to:', '["Treat bacterial infections", "Reduce anxiety and agitation, and provide sedation", "Lower blood pressure directly", "Reverse neuromuscular blockade"]'::jsonb, 1, 'Benzodiazepines are anxiolytic/sedative agents used to reduce anxiety, agitation, and to provide sedation, sometimes alongside seizure management.', 'ICU Pharmacology', '💊', true),
(3086, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'Hypnotic drugs, as a pharmacological class, are primarily used to:', '["Induce and maintain sleep", "Treat hypertension", "Reverse anticoagulation", "Increase heart rate"]'::jsonb, 0, 'Hypnotics are a class of drugs used specifically to induce and/or maintain sleep.', 'ICU Pharmacology', '💊', true),
(3087, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'Analgesic drug selection in a critically ill patient should be guided primarily by:', '["The cheapest available option regardless of pain severity", "A validated pain assessment tool and the severity/type of pain", "The nurse''s personal preference", "Avoiding all analgesia to prevent sedation"]'::jsonb, 1, 'Analgesic choice and dosing should be guided by structured pain assessment (using a validated pain scale) matched to the severity and nature of the patient''s pain.', 'ICU Pharmacology', '💊', true),
(3088, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'Muscle relaxants used peri-operatively can be broadly classed as depolarising (e.g. succinylcholine) or non-depolarising (e.g. vecuronium, atracurium). A key clinical difference is that succinylcholine:', '["Has a slow onset and very long duration", "Has a rapid onset and short duration, useful for rapid sequence intubation", "Cannot be reversed under any circumstances", "Is never associated with malignant hyperthermia"]'::jsonb, 1, 'Succinylcholine''s rapid onset and short duration make it the classic choice for rapid sequence intubation, though it carries a recognised risk of triggering malignant hyperthermia in susceptible patients.', 'ICU Pharmacology', '💊', true),
(3089, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'When a critically ill patient develops signs of an anaphylactic drug reaction (hypotension, stridor, urticaria), the first-line emergency drug treatment is:', '["Oral antihistamine only", "Intramuscular adrenaline (epinephrine)", "Intravenous furosemide", "Oral corticosteroids only"]'::jsonb, 1, 'IM adrenaline is the first-line, life-saving treatment for anaphylaxis, given promptly alongside airway/breathing/circulation support.', 'ICU Pharmacology', '💊', true),
(3090, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'Antihypertensive drugs used in a hypertensive emergency in the ICU are typically administered:', '["Only orally, never intravenously", "As IV infusions that are carefully titrated with continuous blood pressure monitoring", "Without any monitoring since they are always safe", "Only once per day regardless of readings"]'::jsonb, 1, 'In a hypertensive emergency, IV antihypertensives are titrated carefully with continuous BP monitoring to avoid dropping pressure too quickly, which can cause organ hypoperfusion.', 'ICU Pharmacology', '💊', true),
(3091, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'Vasodilator drugs (e.g. nitroglycerin) are used in critical care primarily to:', '["Increase peripheral vascular resistance", "Reduce preload/afterload and improve coronary blood flow", "Cause bronchoconstriction", "Directly treat infection"]'::jsonb, 1, 'Vasodilators such as nitroglycerin reduce preload and/or afterload, easing cardiac workload and improving coronary perfusion, useful in conditions like angina and heart failure.', 'ICU Pharmacology', '💊', true),
(3092, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'A patient develops rapidly rising temperature, muscle rigidity and tachycardia shortly after receiving succinylcholine and a volatile anaesthetic. The priority drug treatment is:', '["Paracetamol", "IV dantrolene plus active cooling", "Oral antibiotics", "Insulin infusion"]'::jsonb, 1, 'This presentation is malignant hyperthermia — IV dantrolene is the specific emergency treatment, given alongside stopping the trigger agent and active cooling measures.', 'ICU Pharmacology', '💊', true),
(3093, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'Prophylactic antibiotics given before surgery are ideally administered:', '["More than 6 hours before incision", "Within about 60 minutes before surgical incision", "Only after the wound is closed", "Only if the patient develops a fever post-operatively"]'::jsonb, 1, 'Surgical antibiotic prophylaxis is most effective when given within roughly 60 minutes before incision, ensuring adequate tissue levels at the time of surgery.', 'ICU Pharmacology', '💊', true),
(3094, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'Digoxin toxicity classically presents with which combination of features?', '["Hypertension and tachycardia only", "Nausea, visual disturbances (e.g. yellow-green halos), and arrhythmias", "Fever and rash only", "Polyuria with no cardiac signs"]'::jsonb, 1, 'Digoxin toxicity classically causes gastrointestinal symptoms, visual disturbances such as yellow-green halos, and cardiac arrhythmias, often worsened by hypokalaemia.', 'ICU Pharmacology', '💊', true),
(3095, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'A patient on furosemide (a loop diuretic) should be monitored closely for which electrolyte disturbance?', '["Hyperkalaemia", "Hypokalaemia", "Hypernatraemia only", "Hypercalcaemia only"]'::jsonb, 1, 'Loop diuretics like furosemide promote potassium loss and commonly cause hypokalaemia, requiring regular electrolyte monitoring.', 'ICU Pharmacology', '💊', true),
(3096, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'Insulin infusions used to manage diabetic ketoacidosis (DKA) in the ICU require close monitoring of:', '["Blood glucose and potassium levels", "Only blood pressure", "Only respiratory rate", "Only body temperature"]'::jsonb, 0, 'Insulin drives potassium into cells alongside glucose, so both blood glucose and serum potassium must be closely monitored during DKA insulin therapy to prevent hypoglycaemia and hypokalaemia.', 'ICU Pharmacology', '💊', true),
(3097, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'Anticoagulant therapy with heparin requires monitoring of which laboratory value to guide dosing?', '["Activated Partial Thromboplastin Time (aPTT)", "Random blood glucose", "Serum sodium", "Liver function tests only"]'::jsonb, 0, 'aPTT is used to monitor and titrate unfractionated heparin therapy to maintain a therapeutic anticoagulation range.', 'ICU Pharmacology', '💊', true),
(3098, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'Warfarin therapy is monitored using which laboratory test?', '["aPTT", "INR (International Normalised Ratio)", "Full blood count only", "Serum creatinine only"]'::jsonb, 1, 'Warfarin''s anticoagulant effect is monitored via the INR, which standardises prothrombin time results across laboratories.', 'ICU Pharmacology', '💊', true),
(3099, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'A key nursing responsibility when a patient is receiving a continuous vasopressor infusion (e.g. noradrenaline) is to:', '["Administer it via a peripheral line preferentially for long-term use", "Administer via a central line where possible, and monitor blood pressure closely with dose titration", "Stop the infusion abruptly whenever blood pressure normalises", "Avoid any haemodynamic monitoring"]'::jsonb, 1, 'Vasopressors like noradrenaline are ideally given via central access (extravasation risk peripherally) with continuous haemodynamic monitoring and careful, gradual titration/weaning.', 'ICU Pharmacology', '💊', true),
(3100, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'Sedative and analgesic infusions in ICU are ideally interrupted daily (a ''sedation holiday'' or spontaneous awakening trial) mainly to:', '["Increase total sedative dose requirements", "Allow neurological assessment and reduce duration of mechanical ventilation/delirium risk", "Save on drug costs only", "Reduce nursing workload"]'::jsonb, 1, 'Daily sedation interruption allows accurate neurological assessment and has been shown to reduce duration of mechanical ventilation and delirium risk when combined with spontaneous breathing trials.', 'ICU Pharmacology', '💊', true),
(3101, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'Which of the following best describes the purpose of stress-ulcer prophylaxis (e.g. proton pump inhibitors) in critically ill patients?', '["To treat active pneumonia", "To reduce the risk of stress-related gastrointestinal bleeding in high-risk ICU patients", "To lower blood glucose", "To prevent deep vein thrombosis"]'::jsonb, 1, 'Stress-ulcer prophylaxis with agents such as proton pump inhibitors reduces the risk of stress-related mucosal bleeding in high-risk critically ill patients (e.g. those on mechanical ventilation or with coagulopathy).', 'ICU Pharmacology', '💊', true),
(3102, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'When calculating an IV infusion rate for a weight-based critical care drug, which piece of information is essential and must always be verified?', '["The patient''s shoe size", "The patient''s current accurate weight (in kg) and the prescribed dose per kg", "The colour of the infusion bag", "The time of day only"]'::jsonb, 1, 'Weight-based infusion calculations require an accurate, current patient weight in kilograms matched against the prescribed dose per kilogram to avoid dosing errors.', 'ICU Pharmacology', '💊', true),
(3103, 'Applied Pharmacology (CCN 414)', 'AI Practice Question', 'Bronchodilator nebulisers (e.g. salbutamol) can cause which common side effect that the nurse should monitor for?', '["Bradycardia and sedation", "Tachycardia and tremor", "Hypoglycaemia", "Weight gain"]'::jsonb, 1, 'Beta-2 agonist bronchodilators commonly cause tachycardia and fine tremor as expected sympathomimetic side effects.', 'ICU Pharmacology', '💊', true),
(3104, 'Ethico-Legal Issues (CCN 424)', 'AI Practice Question', 'Which ethical principle refers to a patient''s right to make their own healthcare decisions?', '["Beneficence", "Autonomy", "Non-maleficence", "Justice"]'::jsonb, 1, 'Autonomy is the ethical principle recognising a competent patient''s right to self-determination in healthcare decisions.', 'Ethics, Law & Management', '⚖️', true),
(3105, 'Ethico-Legal Issues (CCN 424)', 'AI Practice Question', '''Non-maleficence'' as an ethical principle means:', '["Doing good for the patient", "Doing no harm to the patient", "Being fair and just to all patients", "Being honest with the patient"]'::jsonb, 1, 'Non-maleficence is the principle of ''first, do no harm'' — avoiding actions that could injure the patient.', 'Ethics, Law & Management', '⚖️', true),
(3106, 'Ethico-Legal Issues (CCN 424)', 'AI Practice Question', 'For informed consent to be legally valid, it must include all of the following EXCEPT:', '["Adequate information given to the patient", "Patient capacity to understand the information", "Voluntary agreement, free from coercion", "Approval from a family member instead of the patient, when the patient has full capacity"]'::jsonb, 3, 'When a patient has full decision-making capacity, valid consent must come from the patient themselves — a family member cannot substitute for a capable adult''s own consent.', 'Ethics, Law & Management', '⚖️', true),
(3107, 'Ethico-Legal Issues (CCN 424)', 'AI Practice Question', 'Which four elements must all be proven for a nurse to be found legally negligent?', '["Duty of care, breach of duty, harm, and breach causing the harm", "Intent, motive, opportunity, and consequence", "Consent, capacity, communication, and confidentiality", "Only that harm occurred, regardless of cause"]'::jsonb, 0, 'Negligence requires proof of all four elements: a duty of care existed, that duty was breached, harm resulted, and the breach directly caused the harm.', 'Ethics, Law & Management', '⚖️', true),
(3108, 'Ethico-Legal Issues (CCN 424)', 'AI Practice Question', 'The doctrine of ''Res Ipsa Loquitur'' (''the thing speaks for itself'') applies when:', '["A patient explicitly consents to a risky procedure", "An injury is of a type that would not normally occur without someone''s negligence (e.g. a retained surgical instrument)", "A nurse documents care accurately", "A patient refuses treatment"]'::jsonb, 1, 'Res Ipsa Loquitur allows negligence to be inferred from the very nature of an injury that ordinarily wouldn''t happen without negligence, such as a foreign object left inside a patient after surgery.', 'Ethics, Law & Management', '⚖️', true),
(3109, 'Ethico-Legal Issues (CCN 424)', 'AI Practice Question', '''Good Samaritan Laws'' are designed to:', '["Require all healthcare workers to always intervene in emergencies", "Provide some legal protection to those who voluntarily give reasonable emergency assistance in good faith outside their normal duty", "Protect only doctors, not nurses", "Allow any level of care without accountability"]'::jsonb, 1, 'Good Samaritan Laws offer legal protection to individuals (including off-duty healthcare workers) who provide reasonable emergency assistance in good faith, encouraging bystander intervention.', 'Ethics, Law & Management', '⚖️', true),
(3110, 'Ethico-Legal Issues (CCN 424)', 'AI Practice Question', 'An Advance Directive is best described as:', '["A document created by hospital staff without patient input", "A statement made in advance by a patient outlining their wishes for future medical care if they become unable to decide for themselves", "A legal requirement for all surgical patients", "Only applicable to patients over the age of 80"]'::jsonb, 1, 'An Advance Directive lets a patient specify, in advance, their wishes for future care in case they later lose decision-making capacity.', 'Ethics, Law & Management', '⚖️', true),
(3111, 'Ethico-Legal Issues (CCN 424)', 'AI Practice Question', 'A Do-Not-Resuscitate (DNR) order should be:', '["Assumed automatically for all elderly patients", "Clearly documented in the medical record and communicated to the entire care team", "Kept verbal only, never written", "Decided solely by the nurse without physician or patient/family involvement"]'::jsonb, 1, 'A DNR order must be explicitly documented and clearly communicated to the whole care team to avoid confusion during an emergency.', 'Ethics, Law & Management', '⚖️', true),
(3112, 'Ethico-Legal Issues (CCN 424)', 'AI Practice Question', 'The core legal/professional principle behind nursing documentation is best summarised as:', '["''If it wasn''t documented, it wasn''t done''", "Documentation is optional if care was given correctly", "Only negative events need to be documented", "Documentation can be completed weeks later without issue"]'::jsonb, 0, 'Accurate, timely documentation is a nurse''s primary legal protection — undocumented care is very difficult to prove was ever given.', 'Ethics, Law & Management', '⚖️', true),
(3113, 'Ethico-Legal Issues (CCN 424)', 'AI Practice Question', 'Breach of patient confidentiality without lawful justification may expose a nurse to which type of legal action?', '["No consequence, since nurses have full immunity", "Civil liability for breach of confidentiality/privacy", "Only a verbal warning with no formal process", "Automatic loss of citizenship"]'::jsonb, 1, 'Unjustified disclosure of confidential patient information can expose a nurse to civil liability for breach of confidentiality.', 'Ethics, Law & Management', '⚖️', true),
(3114, 'Ethico-Legal Issues (CCN 424)', 'AI Practice Question', '''Battery'' in a legal/nursing context refers to:', '["A device that powers medical equipment", "Unlawful physical contact with a patient without consent", "A type of medication error", "A category of documentation"]'::jsonb, 1, 'Battery is the legal term for unlawful, unconsented physical contact — performing a procedure without valid consent can constitute battery.', 'Ethics, Law & Management', '⚖️', true),
(3115, 'Ethico-Legal Issues (CCN 424)', 'AI Practice Question', 'When a mentally disturbed patient refuses urgently needed treatment, the nurse''s first legal/ethical consideration should be:', '["Force treatment immediately without further assessment", "Assess the patient''s decision-making capacity, since impaired capacity may change the legal basis for consent", "Ignore the refusal and proceed as normal", "Discharge the patient immediately"]'::jsonb, 1, 'Capacity assessment is central — if a patient lacks capacity due to mental disturbance, different legal and ethical frameworks for consent and best-interest decisions may apply.', 'Ethics, Law & Management', '⚖️', true),
(3116, 'Ethico-Legal Issues (CCN 424)', 'AI Practice Question', 'Gunshot wounds, stab wounds and certain other injury types encountered in the emergency department typically require the nurse/team to:', '["Ignore any reporting requirements", "Report to the police/relevant authorities as required by law, in addition to providing clinical care", "Discharge the patient before treating them", "Withhold treatment until police arrive"]'::jsonb, 1, 'Many jurisdictions legally require certain injuries (e.g. gunshot/stab wounds) to be reported to authorities, alongside — not instead of — prompt clinical care.', 'Ethics, Law & Management', '⚖️', true),
(3117, 'Ethico-Legal Issues (CCN 424)', 'AI Practice Question', 'Euthanasia, in the context of medical ethics, refers to:', '["Standard end-of-life comfort/palliative care", "The deliberate act of ending a person''s life to relieve suffering", "A type of anaesthesia used in surgery", "Routine resuscitation"]'::jsonb, 1, 'Euthanasia refers to deliberately ending a person''s life to end suffering, distinct from palliative/comfort care which focuses on symptom relief without hastening death.', 'Ethics, Law & Management', '⚖️', true),
(3118, 'Ethico-Legal Issues (CCN 424)', 'AI Practice Question', 'The ethical principle of ''justice'' in healthcare primarily concerns:', '["Being truthful with patients", "Fair and equitable distribution of healthcare resources and treatment", "Avoiding harm to patients", "Keeping promises made to patients"]'::jsonb, 1, 'Justice in healthcare ethics relates to fairness — ensuring resources, risks and benefits of care are distributed equitably among patients.', 'Ethics, Law & Management', '⚖️', true),
(3119, 'Ethico-Legal Issues (CCN 424)', 'AI Practice Question', '''Veracity'' as an ethical principle in nursing means:', '["Loyalty and faithfulness to commitments", "Truthfulness and honesty with patients", "Fairness in resource distribution", "Avoiding harm"]'::jsonb, 1, 'Veracity is the ethical duty to be truthful and honest with patients about their condition and care.', 'Ethics, Law & Management', '⚖️', true),
(3120, 'Ethico-Legal Issues (CCN 424)', 'AI Practice Question', '''Fidelity'' as an ethical principle in nursing practice means:', '["Being honest at all times", "Keeping promises and remaining faithful to professional commitments made to patients", "Distributing resources fairly", "Avoiding harm to patients"]'::jsonb, 1, 'Fidelity refers to a nurse''s duty to keep promises and remain faithful to the commitments and obligations owed to patients.', 'Ethics, Law & Management', '⚖️', true),
(3121, 'Ethico-Legal Issues (CCN 424)', 'AI Practice Question', 'When a patient with full decision-making capacity refuses treatment against medical advice, the nurse should primarily:', '["Physically restrain the patient to force treatment", "Respect the patient''s autonomous decision, ensure they are fully informed of risks, and document the refusal clearly", "Discharge the patient without any documentation", "Ignore the refusal and treat anyway"]'::jsonb, 1, 'A capacitated patient has the right to refuse treatment — the nurse''s role is to ensure they understand the risks, respect their decision, and thoroughly document the refusal.', 'Ethics, Law & Management', '⚖️', true),
(3122, 'Ethico-Legal Issues (CCN 424)', 'AI Practice Question', 'An ''ethical dilemma'' in nursing practice is best defined as a situation where:', '["There is a single, obviously correct course of action", "Two or more ethical principles conflict, with no single clearly right answer", "The nurse simply lacks clinical knowledge", "Legal guidelines are perfectly clear and non-conflicting"]'::jsonb, 1, 'An ethical dilemma arises when competing ethical principles (e.g. autonomy vs. beneficence) conflict, making the ''right'' choice genuinely unclear.', 'Ethics, Law & Management', '⚖️', true),
(3123, 'Ethico-Legal Issues (CCN 424)', 'AI Practice Question', 'The role of a national nursing regulatory council (e.g. NMCN) primarily includes:', '["Setting and enforcing standards of practice, registering/licensing nurses, and handling professional misconduct", "Only organising social events for nurses", "Setting hospital drug prices", "Managing hospital construction projects"]'::jsonb, 0, 'Nursing regulatory bodies set professional standards, register/license practitioners, and address professional misconduct to protect the public.', 'Ethics, Law & Management', '⚖️', true),
(3124, 'Ethico-Legal Issues (CCN 424)', 'AI Practice Question', 'When police request information or evidence from a nurse about a patient, the nurse should generally:', '["Freely disclose all information immediately without question", "Follow institutional policy and legal requirements, disclosing only what is legally required/authorised, often after consulting a supervisor", "Refuse to speak to police under any circumstance", "Provide false information to protect the patient"]'::jsonb, 1, 'Nurses must balance confidentiality obligations with legal requirements — disclosure to police should follow institutional policy and applicable law, typically with supervisory/legal guidance.', 'Ethics, Law & Management', '⚖️', true),
(3125, 'Ethico-Legal Issues (CCN 424)', 'AI Practice Question', 'Malpractice differs from ordinary negligence mainly in that malpractice specifically refers to:', '["Any mistake made by any person in any profession", "Professional negligence committed by a person with specialised training/skill (e.g. a nurse or doctor) that falls below the accepted standard of care", "Only intentional criminal acts", "Administrative paperwork errors only"]'::jsonb, 1, 'Malpractice is professional negligence specifically — a failure by a trained professional to meet the accepted standard of care within their field.', 'Ethics, Law & Management', '⚖️', true),
(3126, 'Ethico-Legal Issues (CCN 424)', 'AI Practice Question', 'Care of a deceased patient in the critical care unit should include:', '["Immediate disposal with no documentation", "Dignified handling of the body, appropriate documentation, and support for the family, following institutional/legal protocol", "Ignoring family requests entirely", "Removing all lines and tubes immediately regardless of any medico-legal investigation requirements"]'::jsonb, 1, 'Care of the deceased requires dignity, accurate documentation, family support, and awareness that in some cases (e.g. unexpected/suspicious death) lines/evidence must be preserved for medico-legal investigation.', 'Ethics, Law & Management', '⚖️', true),
(3127, 'Ethico-Legal Issues (CCN 424)', 'AI Practice Question', 'A patient''s ''Bill of Rights'' in a healthcare setting typically guarantees, among other things, the right to:', '["Demand any treatment regardless of clinical appropriateness", "Receive respectful care, be informed about their condition/treatment, and participate in care decisions", "Access other patients'' medical records", "Refuse to pay for any care received"]'::jsonb, 1, 'Patient Bills of Rights typically guarantee respectful treatment, the right to information about one''s condition and treatment, and participation in care decisions.', 'Ethics, Law & Management', '⚖️', true),
(3128, 'Ethico-Legal Issues (CCN 424)', 'AI Practice Question', 'Handing over patient care at shift change (handover/handing-taking-over) is legally and clinically important primarily because:', '["It is purely a formality with no real clinical value", "Incomplete or inaccurate handover can lead to errors and gaps in continuity of care, with legal implications if harm results", "It replaces the need for any documentation", "It is only required once per week"]'::jsonb, 1, 'Handover ensures continuity of care; poor handover is a recognised contributor to clinical errors and carries legal implications if patient harm results from missed information.', 'Ethics, Law & Management', '⚖️', true),
(3129, 'Ethico-Legal Issues (CCN 424)', 'AI Practice Question', 'Autonomy as an ethical principle may be ethically limited or overridden in situations where:', '["The patient simply disagrees with the nurse''s opinion", "The patient lacks decision-making capacity, or the decision poses a serious risk to others (e.g. certain public health situations)", "The patient is elderly", "The treatment is expensive"]'::jsonb, 1, 'Autonomy can be ethically limited when a patient lacks capacity to make an informed decision, or in specific situations where a decision poses serious risk to others (e.g. certain infectious disease control measures).', 'Ethics, Law & Management', '⚖️', true),
(3130, 'Ethico-Legal Issues (CCN 424)', 'AI Practice Question', 'An incident report following a medication error should be:', '["Avoided to prevent blame", "Completed factually and promptly, focusing on what happened rather than assigning blame, to support learning and prevent recurrence", "Only completed if the patient was seriously harmed", "Written a week later once the nurse has ''calmed down''"]'::jsonb, 1, 'Incident reports should be factual and prompt, supporting a ''just culture'' focused on system learning and prevention rather than blame — and completed regardless of whether harm occurred.', 'Ethics, Law & Management', '⚖️', true),
(3131, 'Ethico-Legal Issues (CCN 424)', 'AI Practice Question', 'The ''off-duty nurse'' encountering an emergency outside of work is generally:', '["Legally forbidden from providing any assistance", "Not obligated in most jurisdictions to intervene, but may be protected by Good Samaritan provisions if they choose to help in good faith", "Required to provide full ICU-level care regardless of setting", "Automatically liable for any bad outcome if they help"]'::jsonb, 1, 'In most jurisdictions an off-duty nurse is not legally obligated to intervene, but Good Samaritan protections generally apply if they choose to render reasonable emergency assistance in good faith.', 'Ethics, Law & Management', '⚖️', true),
(3132, 'Ethico-Legal Issues (CCN 424)', 'AI Practice Question', 'Reportable cases in emergency nursing practice typically include which of the following?', '["Routine minor illnesses only", "Suspected abuse/assault, certain infectious diseases, and specific injury types (e.g. gunshot wounds) as defined by law/policy", "Only cases where the patient requests reporting", "Cases where the patient has private insurance only"]'::jsonb, 1, 'Certain categories — suspected abuse, notifiable infectious diseases, and specific violent injury types — are legally reportable regardless of patient preference.', 'Ethics, Law & Management', '⚖️', true),
(3133, 'Ethico-Legal Issues (CCN 424)', 'AI Practice Question', 'The ''Beneficence'' principle obligates the nurse to:', '["Simply avoid causing harm", "Actively act in ways that promote the patient''s wellbeing and best interests", "Distribute resources equally", "Always follow the patient''s exact instructions regardless of clinical judgement"]'::jsonb, 1, 'Beneficence goes beyond avoiding harm (non-maleficence) — it obligates the nurse to actively act for the patient''s good and wellbeing.', 'Ethics, Law & Management', '⚖️', true),
(3134, 'Ethico-Legal Issues (CCN 424)', 'AI Practice Question', 'A key legal pitfall for critical care nurses relates to:', '["Over-documentation of routine, accurate observations", "Failure to timely report a significant change in patient condition to the physician", "Following unit protocols correctly", "Providing patient education"]'::jsonb, 1, 'Failing to promptly recognise and report a significant deterioration is a recognised legal pitfall, as delayed escalation can directly contribute to patient harm.', 'Ethics, Law & Management', '⚖️', true),
(3135, 'Ethico-Legal Issues (CCN 424)', 'AI Practice Question', 'Substance-abuse patients presenting to the emergency department raise particular legal/ethical considerations mainly regarding:', '["Automatic denial of all treatment", "Capacity to consent, potential for withdrawal complications, and confidentiality of sensitive information", "No special considerations apply", "Mandatory permanent hospitalisation"]'::jsonb, 1, 'Substance-affected patients raise particular concerns around fluctuating capacity to consent, medical risks of withdrawal, and heightened confidentiality sensitivity.', 'Ethics, Law & Management', '⚖️', true),
(3136, 'Management & Teaching (GST 420)', 'AI Practice Question', 'The five classic functions of management are best listed as:', '["Planning, Organising, Staffing, Directing, Controlling", "Diagnosing, Prescribing, Treating, Evaluating, Discharging", "Assessing, Planning, Implementing, Evaluating, Documenting", "Hiring, Firing, Paying, Training, Promoting"]'::jsonb, 0, 'The classic management functions are Planning, Organising, Staffing, Directing and Controlling.', 'Ethics, Law & Management', '⚖️', true),
(3137, 'Management & Teaching (GST 420)', 'AI Practice Question', 'An autocratic leadership style is generally most appropriate in which situation?', '["Routine, low-stakes team planning meetings", "A cardiac arrest or other critical emergency requiring rapid, directive decision-making", "Long-term staff professional development planning", "Resolving a minor interpersonal disagreement"]'::jsonb, 1, 'Autocratic (directive) leadership, where the leader makes rapid decisions with limited consultation, is well-suited to critical emergencies where speed is essential.', 'Ethics, Law & Management', '⚖️', true),
(3138, 'Management & Teaching (GST 420)', 'AI Practice Question', 'A democratic leadership style is characterised by:', '["The leader making all decisions alone with no team input", "Team members being actively involved in decision-making alongside the leader", "A complete absence of leadership direction", "Decisions made only by external authorities"]'::jsonb, 1, 'Democratic leadership involves the team in decision-making, which tends to increase engagement and buy-in, though it can be slower than autocratic decision-making.', 'Ethics, Law & Management', '⚖️', true),
(3139, 'Management & Teaching (GST 420)', 'AI Practice Question', 'When a nurse delegates a task to another team member, which of the following remains true?', '["The delegating nurse is no longer accountable for the outcome", "Authority for the task can be delegated, but accountability for the overall outcome remains with the delegating nurse", "The delegate assumes full legal accountability instead", "Delegation removes the need for any supervision"]'::jsonb, 1, 'While the authority to perform a task can be delegated, the delegating nurse retains accountability for ensuring the task was appropriate to delegate and appropriately supervised.', 'Ethics, Law & Management', '⚖️', true),
(3140, 'Management & Teaching (GST 420)', 'AI Practice Question', 'The ''5 Rights of Delegation'' include right task, right circumstance, right person, right direction/communication, and:', '["Right documentation only", "Right supervision/evaluation", "Right payment", "Right uniform"]'::jsonb, 1, 'The 5 Rights of Delegation are: right task, right circumstance, right person, right direction/communication, and right supervision/evaluation.', 'Ethics, Law & Management', '⚖️', true),
(3141, 'Management & Teaching (GST 420)', 'AI Practice Question', 'The first step in an effective risk management cycle is typically to:', '["Implement a control plan immediately without analysis", "Identify the risk", "Report the incident to the media", "Terminate the staff member involved"]'::jsonb, 1, 'Risk management begins with identifying potential risks before they can be analysed, prioritised and controlled.', 'Ethics, Law & Management', '⚖️', true),
(3142, 'Management & Teaching (GST 420)', 'AI Practice Question', 'Incident reporting within a hospital''s risk management programme primarily serves to:', '["Assign individual blame for punishment", "Identify system issues and prevent recurrence of adverse events", "Increase hospital billing", "Reduce the number of staff on duty"]'::jsonb, 1, 'Incident reporting is a core risk-management tool for identifying systemic issues and implementing changes to prevent similar events from recurring.', 'Ethics, Law & Management', '⚖️', true),
(3143, 'Management & Teaching (GST 420)', 'AI Practice Question', 'According to adult learning principles (andragogy), adults learn best when the content is:', '["Abstract, theoretical, and disconnected from real experience", "Relevant, problem-centred, and builds on their prior experience", "Delivered purely through passive lecture with no interaction", "Identical regardless of the learner''s background"]'::jsonb, 1, 'Andragogy emphasises that adult learners engage best with relevant, problem-centred material that connects to and builds upon their existing experience.', 'Ethics, Law & Management', '⚖️', true),
(3144, 'Management & Teaching (GST 420)', 'AI Practice Question', 'When teaching a patient a new self-care skill, the most reliable way to evaluate their understanding is to:', '["Ask ''Do you understand?'' and accept a yes/no answer", "Use the ''teach-back'' method, asking the patient to explain or demonstrate the skill themselves", "Assume understanding if the patient nods", "Skip evaluation entirely to save time"]'::jsonb, 1, 'The teach-back method — having the patient explain or demonstrate what they learned in their own words — is a far more reliable check of true understanding than a simple yes/no question.', 'Ethics, Law & Management', '⚖️', true),
(3145, 'Management & Teaching (GST 420)', 'AI Practice Question', 'The correct order of the health education/teaching cycle is:', '["Deliver → Assess → Evaluate → Set objectives", "Assess learning needs → Set objectives → Select teaching method → Deliver → Evaluate", "Evaluate → Deliver → Assess → Objectives", "There is no defined order — any sequence works equally well"]'::jsonb, 1, 'An effective teaching cycle begins with assessing learning needs, then setting objectives, selecting an appropriate method, delivering the teaching, and finally evaluating understanding.', 'Ethics, Law & Management', '⚖️', true),
(3146, 'Management & Teaching (GST 420)', 'AI Practice Question', 'Herzberg''s Two-Factor Theory of motivation distinguishes between:', '["Physical needs and psychological needs only", "Hygiene factors (e.g. salary, working conditions) and true motivators (e.g. achievement, recognition)", "Autonomy and beneficence", "Planning and controlling"]'::jsonb, 1, 'Herzberg''s theory separates ''hygiene factors'' (which prevent dissatisfaction but don''t motivate) from ''motivators'' (which actively drive satisfaction and performance, such as achievement and recognition).', 'Ethics, Law & Management', '⚖️', true),
(3147, 'Management & Teaching (GST 420)', 'AI Practice Question', 'In Maslow''s hierarchy of needs, which level must generally be met before higher-level needs such as self-actualisation are pursued?', '["Self-actualisation needs first, then physiological needs", "Basic physiological needs (e.g. food, water, safety)", "Esteem needs only", "There is no hierarchy — all needs are equal"]'::jsonb, 1, 'Maslow''s hierarchy holds that basic physiological and safety needs generally must be reasonably met before an individual can focus on higher-level needs like esteem or self-actualisation.', 'Ethics, Law & Management', '⚖️', true),
(3148, 'Management & Teaching (GST 420)', 'AI Practice Question', 'Effective interdepartmental communication and relationships within a hospital primarily support:', '["Isolated, siloed working with no need for coordination", "Coordinated, safe and efficient patient care across departments", "Competition between departments for resources only", "Reduced accountability for any single department"]'::jsonb, 1, 'Good interdepartmental communication supports coordinated care, reduces errors at handover points between departments, and improves overall efficiency and safety.', 'Ethics, Law & Management', '⚖️', true),
(3149, 'Management & Teaching (GST 420)', 'AI Practice Question', 'Staffing, as a management function, primarily involves:', '["Setting the annual hospital budget only", "Recruiting, hiring, orienting and scheduling appropriately qualified personnel", "Designing the physical layout of the ward", "Writing hospital policy documents"]'::jsonb, 1, 'Staffing covers recruiting, hiring, orienting and appropriately scheduling personnel to meet patient care needs.', 'Ethics, Law & Management', '⚖️', true),
(3150, 'Management & Teaching (GST 420)', 'AI Practice Question', '''Job performance evaluation'' as part of the Controlling management function is primarily used to:', '["Punish underperforming staff exclusively", "Assess performance against standards, provide feedback, and guide staff development", "Reduce the total number of staff", "Replace the need for staff supervision entirely"]'::jsonb, 1, 'Performance evaluation compares actual performance to expected standards, providing constructive feedback and identifying development needs — not merely punitive action.', 'Ethics, Law & Management', '⚖️', true),
(3151, 'Management & Teaching (GST 420)', 'AI Practice Question', '''The learning environment'', when planning patient/staff education, refers to:', '["Only the physical classroom or bedside space", "The physical, psychological and social conditions that influence how effectively learning occurs", "A concept that has no bearing on teaching effectiveness", "Only the equipment used during teaching"]'::jsonb, 1, 'The learning environment includes physical comfort, psychological safety, and social factors — all of which influence how effectively a learner absorbs new information.', 'Ethics, Law & Management', '⚖️', true),
(3152, 'Management & Teaching (GST 420)', 'AI Practice Question', 'A laissez-faire leadership style is best described as:', '["Highly directive with constant close supervision", "A largely hands-off approach giving team members significant independence and minimal direct guidance", "Identical to autocratic leadership", "Only usable in emergency situations"]'::jsonb, 1, 'Laissez-faire leadership gives team members significant autonomy with minimal direct oversight, which can work well with highly experienced, self-directed teams but poorly in high-risk or novice situations.', 'Ethics, Law & Management', '⚖️', true),
(3153, 'Management & Teaching (GST 420)', 'AI Practice Question', 'When evaluating whether a teaching/health education session was effective, the nurse should primarily assess:', '["Whether the session ran on schedule only", "Whether the learner''s knowledge, skills or behaviour actually changed as intended", "How many slides were used", "The room temperature during the session"]'::jsonb, 1, 'Effectiveness of teaching is judged by whether the intended change in the learner''s knowledge, skill, or behaviour was actually achieved — not by process measures like timing.', 'Ethics, Law & Management', '⚖️', true),
(3154, 'Management & Teaching (GST 420)', 'AI Practice Question', '''Authority and accountability'' in a management context means:', '["Authority and accountability are unrelated concepts", "Authority (the right to act/direct others) should be matched with accountability (responsibility for the outcome) at each level", "Only senior managers carry any accountability", "Accountability is optional if authority was granted"]'::jsonb, 1, 'Sound management practice pairs the authority to act or direct others with corresponding accountability for the results of those actions.', 'Ethics, Law & Management', '⚖️', true),
(3155, 'Management & Teaching (GST 420)', 'AI Practice Question', 'Discipline, as part of the Controlling function of management, should ideally be:', '["Applied inconsistently depending on personal relationships", "Fair, consistent, and applied according to established policy", "Avoided entirely regardless of the situation", "Used only as a first response before any coaching or feedback"]'::jsonb, 1, 'Effective disciplinary practice is fair, consistent and policy-based, typically following a progressive approach rather than being the very first response to an issue.', 'Ethics, Law & Management', '⚖️', true),
(3156, 'Management & Teaching (GST 420)', 'AI Practice Question', 'Which teaching method would be most appropriate for teaching a group of new nurses the physical steps of inserting a urinary catheter?', '["A written handout only, with no demonstration", "A hands-on demonstration/return-demonstration approach", "A purely theoretical lecture with no practical component", "No teaching is required for a psychomotor skill"]'::jsonb, 1, 'Psychomotor (hands-on) skills are best taught through demonstration followed by supervised return-demonstration by the learner, not by lecture or reading alone.', 'Ethics, Law & Management', '⚖️', true),
(3157, 'Management & Teaching (GST 420)', 'AI Practice Question', 'The ''politics of healthcare services'', as studied in nursing management, generally refers to:', '["Nurses'' personal political party affiliations", "How power, resource allocation, and organisational decision-making influence healthcare delivery", "A topic with no relevance to nursing practice", "Only national government policy, never hospital-level dynamics"]'::jsonb, 1, 'Healthcare politics examines how power dynamics, resource allocation and organisational decision-making shape the delivery of care at every level, from hospital units to national policy.', 'Ethics, Law & Management', '⚖️', true),
(3158, 'Management & Teaching (GST 420)', 'AI Practice Question', 'Effective ''unit organisation'' in nursing management primarily aims to:', '["Maximise confusion about roles and responsibilities", "Structure staff roles, workflows and resources to deliver safe, efficient patient care on the unit", "Eliminate the need for any leadership role", "Focus solely on cost-cutting regardless of care quality"]'::jsonb, 1, 'Unit organisation structures roles, workflows and resources so the unit can deliver safe and efficient patient care.', 'Ethics, Law & Management', '⚖️', true),
(3159, 'Management & Teaching (GST 420)', 'AI Practice Question', 'A hospital''s ''departmental risk management programme'' typically includes all of the following EXCEPT:', '["Identification of common risk categories", "Incident reporting mechanisms", "Monitoring and evaluation of interventions", "Concealing incidents to protect the department''s reputation"]'::jsonb, 3, 'A genuine risk management programme relies on transparency (identification, reporting, monitoring) — concealing incidents undermines the entire purpose of risk management and patient safety.', 'Ethics, Law & Management', '⚖️', true),
(3160, 'Management & Teaching (GST 420)', 'AI Practice Question', '''Accounting and budgeting'' as part of the Controlling management function primarily involves:', '["Ignoring financial resources entirely, since patient care is the only priority", "Monitoring and managing financial resources to support effective, sustainable unit/department operations", "Only the hospital''s chief financial officer''s responsibility, with no relevance to unit-level nurse managers", "Setting individual staff salaries directly"]'::jsonb, 1, 'Accounting and budgeting involves monitoring and managing financial resources so the unit or department can operate effectively and sustainably — relevant even at the nurse-manager level for supply/staffing budgets.', 'Ethics, Law & Management', '⚖️', true),
(3161, 'Management & Teaching (GST 420)', 'AI Practice Question', 'When health education uses a ''health talk'' format for a group of patients, an important teaching principle to apply is:', '["Using complex medical jargon to appear more credible", "Using simple, clear language appropriate to the audience''s health literacy level", "Making the talk as long as possible regardless of attention span", "Avoiding any opportunity for questions"]'::jsonb, 1, 'Effective health talks use clear, simple language matched to the audience''s health literacy, and allow opportunity for questions to check and reinforce understanding.', 'Ethics, Law & Management', '⚖️', true),
(3162, 'Management & Teaching (GST 420)', 'AI Practice Question', '''Organising'', as a management function, is best defined as:', '["Setting future goals only", "Arranging resources, tasks and structure so goals set in the planning phase can actually be achieved", "Directly supervising day-to-day staff activity", "Evaluating whether goals were met"]'::jsonb, 1, 'Organising involves structuring resources, tasks, and reporting relationships so that the goals established during planning can be effectively carried out.', 'Ethics, Law & Management', '⚖️', true),
(3163, 'Management & Teaching (GST 420)', 'AI Practice Question', 'Communication, as a component of the Directing management function, is critical mainly because:', '["It has no real effect on patient safety", "Poor communication is a leading contributor to clinical errors and adverse events", "It only matters for written reports", "Verbal communication is never subject to error"]'::jsonb, 1, 'Poor communication is consistently identified as a leading root cause of clinical errors and adverse events, making effective communication a critical management responsibility.', 'Ethics, Law & Management', '⚖️', true),
(3164, 'Disaster & Emergency Nursing', 'AI Practice Question', 'In mass casualty triage systems such as START, a casualty who is not breathing even after repositioning the airway is typically categorised as:', '["Immediate (red)", "Delayed (yellow)", "Minor (green)", "Deceased/expectant (black)"]'::jsonb, 3, 'In START triage, a casualty who remains apnoeic after an airway repositioning attempt is categorised as deceased/expectant, since resources are prioritised toward salvageable casualties.', 'Disaster & Emergency Nursing', '🚨', true),
(3165, 'Disaster & Emergency Nursing', 'AI Practice Question', 'The overarching principle guiding resource allocation in a mass casualty disaster response is:', '["Treat whoever arrived first, regardless of severity", "Achieve the greatest good for the greatest number of casualties", "Treat the most severely injured patient first no matter what", "Treat only patients who can pay for care"]'::jsonb, 1, 'Disaster triage is guided by achieving the greatest good for the greatest number, which sometimes means the most critically injured (unsalvageable) casualties are deprioritised in favour of those with a realistic chance of survival.', 'Disaster & Emergency Nursing', '🚨', true),
(3166, 'Disaster & Emergency Nursing', 'AI Practice Question', 'The four recognised phases of disaster management are:', '["Mitigation, Preparedness, Response, Recovery", "Triage, Treatment, Transport, Transfer", "Alert, Alarm, Action, Aftermath", "Warning, Waiting, Working, Winding-down"]'::jsonb, 0, 'Disaster management is classically organised into four phases: Mitigation, Preparedness, Response, and Recovery.', 'Disaster & Emergency Nursing', '🚨', true),
(3167, 'Disaster & Emergency Nursing', 'AI Practice Question', 'The correct order of the ABCDE primary survey in trauma/emergency assessment is:', '["Airway, Breathing, Circulation, Disability, Exposure", "Breathing, Airway, Disability, Circulation, Exposure", "Circulation, Airway, Breathing, Exposure, Disability", "Disability, Airway, Breathing, Circulation, Exposure"]'::jsonb, 0, 'The ABCDE approach prioritises Airway (with C-spine control), Breathing, Circulation (with haemorrhage control), Disability (neuro status), then Exposure/Environment.', 'Disaster & Emergency Nursing', '🚨', true),
(3168, 'Disaster & Emergency Nursing', 'AI Practice Question', 'The ''Golden Hour'' concept in trauma care refers to:', '["The first hour after hospital discharge", "The first 60 minutes after major trauma, during which rapid assessment and definitive care most improve survival", "The hour before surgery begins", "A 60-minute waiting period before treatment can start"]'::jsonb, 1, 'The Golden Hour describes the critical first 60 minutes after major trauma, where prompt assessment, stabilisation and definitive care have the greatest impact on survival outcomes.', 'Disaster & Emergency Nursing', '🚨', true),
(3169, 'Disaster & Emergency Nursing', 'AI Practice Question', 'During the Airway step of a primary survey in a trauma patient, the nurse must always also consider:', '["Administering oral fluids", "Cervical spine protection/immobilisation", "Full mobilisation of the patient", "Discharge planning"]'::jsonb, 1, 'In trauma, the airway is assessed and managed together with cervical spine protection, since airway manoeuvres could worsen an unstable spinal injury if the neck isn''t protected.', 'Disaster & Emergency Nursing', '🚨', true),
(3170, 'Disaster & Emergency Nursing', 'AI Practice Question', 'In the ''Circulation'' step of the primary survey, the priority action for active external haemorrhage is:', '["Elevate the limb only, with no direct pressure", "Apply direct pressure (and a tourniquet if needed for life-threatening limb haemorrhage) to control bleeding", "Wait for surgical review before any intervention", "Apply ice only"]'::jsonb, 1, 'Direct pressure — and a tourniquet for life-threatening limb haemorrhage that doesn''t respond to pressure — is the priority intervention to control external bleeding during the Circulation step.', 'Disaster & Emergency Nursing', '🚨', true),
(3171, 'Disaster & Emergency Nursing', 'AI Practice Question', 'During a mass casualty event, the FIRST priority for any responding nurse should be:', '["Treating the most visibly injured casualty immediately, regardless of scene safety", "Ensuring their own personal safety and the safety of the scene before providing care", "Calling family members of casualties", "Documenting the event in detail before any intervention"]'::jsonb, 1, 'Scene/personal safety always comes first — a responder who becomes a casualty themselves adds to the problem instead of helping resolve it.', 'Disaster & Emergency Nursing', '🚨', true),
(3172, 'Disaster & Emergency Nursing', 'AI Practice Question', '''Preparedness'', as a phase of disaster management, primarily involves:', '["Actions taken during the actual disaster event", "Planning, training, drills and stockpiling resources before a disaster occurs", "Long-term rebuilding after a disaster has passed", "Reducing future risk through infrastructure changes only"]'::jsonb, 1, 'Preparedness covers pre-disaster planning activities such as training, drills, and stockpiling supplies, so the response phase can be executed effectively when needed.', 'Disaster & Emergency Nursing', '🚨', true),
(3173, 'Disaster & Emergency Nursing', 'AI Practice Question', '''Mitigation'', as a phase of disaster management, primarily involves:', '["Immediate rescue operations during the disaster", "Actions taken in advance to reduce the severity or likelihood of a disaster''s impact (e.g. building codes, early warning systems)", "Post-disaster psychological counselling", "Triaging casualties at the scene"]'::jsonb, 1, 'Mitigation refers to proactive, long-term actions that reduce the risk or severity of future disasters, such as improved building codes or early warning systems.', 'Disaster & Emergency Nursing', '🚨', true),
(3174, 'Disaster & Emergency Nursing', 'AI Practice Question', '''Recovery'', as the final phase of disaster management, focuses on:', '["Initial casualty triage only", "Long-term restoration of services, infrastructure, and community/psychological wellbeing after a disaster", "Preventing the disaster from ever occurring", "Only financial compensation for victims"]'::jsonb, 1, 'The recovery phase focuses on longer-term restoration of infrastructure, services and psychological wellbeing for the affected community after the acute response has ended.', 'Disaster & Emergency Nursing', '🚨', true),
(3175, 'Disaster & Emergency Nursing', 'AI Practice Question', '''Psychological first aid'' offered to disaster survivors primarily aims to:', '["Provide formal, long-term psychotherapy on-scene", "Offer immediate practical and emotional support to reduce acute distress and promote coping", "Diagnose formal psychiatric conditions on-site", "Replace the need for any follow-up mental health care"]'::jsonb, 1, 'Psychological first aid provides immediate, practical support to reduce acute distress and support coping in the aftermath of a disaster — it is not formal therapy and does not replace follow-up care.', 'Disaster & Emergency Nursing', '🚨', true),
(3176, 'Disaster & Emergency Nursing', 'AI Practice Question', 'In a disaster triage system, a casualty who is breathing normally, has a normal pulse, and can follow simple commands, but has a significant injury that will need treatment, is typically categorised as:', '["Immediate (red)", "Delayed (yellow)", "Minor (green)", "Deceased (black)"]'::jsonb, 1, 'Casualties with serious but not immediately life-threatening injuries — stable enough to wait a short period for treatment — are categorised as delayed (yellow) in most triage systems.', 'Disaster & Emergency Nursing', '🚨', true),
(3177, 'Disaster & Emergency Nursing', 'AI Practice Question', 'A casualty who is walking and talking at a disaster scene, with only minor injuries, is typically triaged as:', '["Immediate (red)", "Delayed (yellow)", "Minor (green)", "Deceased (black)"]'::jsonb, 2, 'Ambulatory casualties with minor injuries (''walking wounded'') are triaged as minor (green), as they do not require immediate intervention.', 'Disaster & Emergency Nursing', '🚨', true),
(3178, 'Disaster & Emergency Nursing', 'AI Practice Question', 'During the primary survey ''Exposure'' step, the nurse should:', '["Leave the patient fully clothed to preserve dignity at all costs, even if injuries are missed", "Fully expose the patient to identify all injuries, while taking care to prevent hypothermia", "Skip this step in all cases to save time", "Only expose the chest, regardless of injury pattern"]'::jsonb, 1, 'Full exposure is needed to identify all injuries, but this must be balanced with actively preventing hypothermia (e.g. using warming blankets) once the assessment is complete.', 'Disaster & Emergency Nursing', '🚨', true),
(3179, 'Disaster & Emergency Nursing', 'AI Practice Question', 'Effective disaster response coordination between a hospital and emergency medical services primarily requires:', '["Each agency working entirely independently with no communication", "Clear communication, pre-established protocols, and a defined command structure", "Only the hospital''s decisions being followed, regardless of on-scene conditions", "No advance planning, since disasters are unpredictable"]'::jsonb, 1, 'Effective coordination relies on clear communication channels, pre-established protocols, and an agreed incident command structure established well before any disaster occurs.', 'Disaster & Emergency Nursing', '🚨', true),
(3180, 'Disaster & Emergency Nursing', 'AI Practice Question', 'The ''Disability'' step of the ABCDE primary survey primarily assesses:', '["The patient''s insurance and financial status", "Neurological status, such as level of consciousness and pupillary response", "Only the presence of physical disabilities pre-existing before the injury", "Skin condition only"]'::jsonb, 1, 'The Disability step evaluates neurological status — level of consciousness (e.g. AVPU or GCS), pupil size/reactivity, and gross motor function.', 'Disaster & Emergency Nursing', '🚨', true),
(3181, 'Disaster & Emergency Nursing', 'AI Practice Question', 'During mass casualty incidents, an Incident Command System (ICS) is used primarily to:', '["Assign one person total, unchecked authority with no structure", "Provide a standardised, scalable command and coordination structure for managing the emergency response", "Eliminate the need for any communication between agencies", "Replace the need for triage entirely"]'::jsonb, 1, 'An Incident Command System provides a standardised, scalable structure for coordinating personnel, resources and communication during an emergency or disaster response.', 'Disaster & Emergency Nursing', '🚨', true),
(3182, 'Disaster & Emergency Nursing', 'AI Practice Question', 'An ''expectant'' casualty classification in disaster triage refers to casualties who:', '["Have only minor injuries and can wait for care", "Have injuries so severe that survival is unlikely even with available resources, so comfort care is prioritised over aggressive intervention", "Are pregnant and require obstetric priority", "Require no medical attention at all"]'::jsonb, 1, '''Expectant'' casualties have injuries so severe that survival is very unlikely given available resources — care shifts to comfort measures so limited resources can be directed to salvageable casualties.', 'Disaster & Emergency Nursing', '🚨', true),
(3183, 'Disaster & Emergency Nursing', 'AI Practice Question', 'Following a disaster, providing accurate and timely documentation of triage decisions and care given is important primarily because it:', '["Has no real value once the emergency has passed", "Supports continuity of care, resource tracking, and legal/quality review of the response", "Is only useful for insurance billing purposes", "Should be skipped to save time during a crisis"]'::jsonb, 1, 'Documentation during disaster response supports continuity of care as casualties move between providers, resource tracking, and later legal and quality review of how the response was managed.', 'Disaster & Emergency Nursing', '🚨', true),
(3184, 'Laboratory Sciences (CCN 426)', 'AI Practice Question', 'Before starting a blood transfusion, the essential bedside safety check is to:', '["Skip patient ID checks if the patient is known to staff", "Verify patient identity and blood unit compatibility with a second qualified checker", "Warm the blood unit in a microwave first", "Only check the blood group on the fridge label, not the patient"]'::jsonb, 1, 'Independent double-checking of patient identity and blood unit compatibility at the bedside is the essential final safety barrier against transfusion errors.', 'Laboratory Sciences & Haematology', '🔬', true),
(3185, 'Laboratory Sciences (CCN 426)', 'AI Practice Question', 'If a patient develops fever, chills, back pain and hypotension shortly after a blood transfusion starts, the nurse should:', '["Slow the infusion slightly and monitor", "Stop the transfusion immediately, keep the IV line open with saline, and notify the physician", "Continue the transfusion at the same rate", "Administer an antihistamine and continue as planned"]'::jsonb, 1, 'Suspected transfusion reaction requires immediately stopping the transfusion, maintaining IV access with saline, and prompt physician notification to prevent further harm.', 'Laboratory Sciences & Haematology', '🔬', true),
(3186, 'Laboratory Sciences (CCN 426)', 'AI Practice Question', 'Management of a sickle cell crisis focuses primarily on:', '["Fluid restriction and cold compresses", "Aggressive hydration, oxygen therapy, and analgesia, plus treating any precipitating infection", "Immediate splenectomy", "Strict bed rest with no other intervention"]'::jsonb, 1, 'Sickle cell crisis management centres on hydration, oxygenation, effective analgesia (often opioids), and identifying/treating any triggering infection.', 'Laboratory Sciences & Haematology', '🔬', true),
(3187, 'Laboratory Sciences (CCN 426)', 'AI Practice Question', 'Disseminated Intravascular Coagulation (DIC) is characterised by:', '["Only excessive clotting, with no bleeding risk", "Simultaneous widespread clotting and bleeding, due to consumption of clotting factors and platelets", "Only bleeding, with no clot formation anywhere", "A condition limited exclusively to the respiratory system"]'::jsonb, 1, 'DIC involves paradoxical widespread microthrombi formation alongside bleeding, as clotting factors and platelets become consumed, often causing organ dysfunction.', 'Laboratory Sciences & Haematology', '🔬', true),
(3188, 'Laboratory Sciences (CCN 426)', 'AI Practice Question', 'A key early clinical sign that should raise suspicion of DIC in a critically ill patient is:', '["Unexplained oozing from IV/puncture sites alongside signs of organ dysfunction", "Isolated mild headache with no other findings", "Normal coagulation results with no bleeding", "Bradycardia alone"]'::jsonb, 0, 'Unexplained oozing from IV sites or wounds, combined with evidence of organ dysfunction from microthrombi, should raise suspicion for DIC and prompt coagulation studies.', 'Laboratory Sciences & Haematology', '🔬', true),
(3189, 'Laboratory Sciences (CCN 426)', 'AI Practice Question', 'Which of the following pathogens is a common cause of ventilator-associated pneumonia (VAP) in the ICU?', '["Pseudomonas aeruginosa", "Common cold rhinovirus only", "Malaria parasite", "Tapeworm"]'::jsonb, 0, 'Pseudomonas aeruginosa is a common and often resistant pathogen implicated in ventilator-associated pneumonia in ICU patients.', 'Laboratory Sciences & Haematology', '🔬', true),
(3190, 'Laboratory Sciences (CCN 426)', 'AI Practice Question', 'Central line-associated bloodstream infection (CLABSI) is best prevented primarily through:', '["Leaving the same central line in place indefinitely regardless of need", "Strict sterile technique during insertion, sterile dressing changes, and prompt removal when no longer needed", "Avoiding hand hygiene to reduce skin irritation", "Using the line for as many purposes as possible simultaneously"]'::jsonb, 1, 'CLABSI prevention relies on sterile insertion technique, meticulous ongoing site care, and removing the line as soon as it is no longer clinically necessary.', 'Laboratory Sciences & Haematology', '🔬', true),
(3191, 'Laboratory Sciences (CCN 426)', 'AI Practice Question', 'Sterilisation, as distinct from disinfection, is defined as a process that:', '["Kills most pathogens but not bacterial spores", "Kills ALL microorganisms, including bacterial spores", "Only reduces the number of organisms, without eliminating any", "Is only relevant to skin antisepsis"]'::jsonb, 1, 'Sterilisation (e.g. via autoclaving) destroys all microorganisms including resistant bacterial spores, unlike disinfection which reduces most pathogens but may not eliminate spores.', 'Laboratory Sciences & Haematology', '🔬', true),
(3192, 'Laboratory Sciences (CCN 426)', 'AI Practice Question', 'Autoclaving is a sterilisation method that primarily uses:', '["Ultraviolet light only", "Pressurised steam at high temperature", "Cold chemical soaking only, with no heat", "Dry air at room temperature"]'::jsonb, 1, 'Autoclaves use pressurised steam at high temperature to achieve sterilisation, effective against even resistant bacterial spores.', 'Laboratory Sciences & Haematology', '🔬', true),
(3193, 'Laboratory Sciences (CCN 426)', 'AI Practice Question', 'Before starting empiric antibiotic therapy in a septic patient, best practice is to:', '["Never send cultures, since they delay treatment", "Obtain blood/relevant cultures first (where feasible), then start empiric antibiotics promptly without waiting for results", "Wait for full culture results (usually 48–72 hours) before giving any antibiotic", "Only send cultures if the patient requests it"]'::jsonb, 1, 'Cultures should be drawn before antibiotics whenever feasible to preserve diagnostic yield, but empiric antibiotic therapy should still begin promptly rather than waiting for results, given the urgency of sepsis.', 'Laboratory Sciences & Haematology', '🔬', true),
(3194, 'Laboratory Sciences (CCN 426)', 'AI Practice Question', 'Culture and sensitivity testing of a clinical specimen is primarily performed to:', '["Identify the causative organism and determine which antibiotics it is sensitive to, guiding targeted therapy", "Measure the patient''s haemoglobin level", "Assess kidney function", "Determine blood type"]'::jsonb, 0, 'Culture and sensitivity testing identifies the specific pathogen and which antibiotics it responds to, allowing antibiotic therapy to be appropriately narrowed/targeted.', 'Laboratory Sciences & Haematology', '🔬', true),
(3195, 'Laboratory Sciences (CCN 426)', 'AI Practice Question', 'Surgical antibiotic prophylaxis is generally recommended to be discontinued:', '["After 7–14 days routinely, regardless of procedure", "Within 24 hours after surgery for most clean procedures, to reduce resistance development", "Only after the patient is fully discharged from hospital", "It should be continued indefinitely for all patients"]'::jsonb, 1, 'For most clean surgical procedures, prophylactic antibiotics should be stopped within 24 hours post-operatively — prolonged unnecessary use increases resistance risk without added benefit.', 'Laboratory Sciences & Haematology', '🔬', true),
(3196, 'Laboratory Sciences (CCN 426)', 'AI Practice Question', 'Which of the following common ICU-acquired pathogens is a fungal organism (rather than bacterial)?', '["Klebsiella pneumoniae", "Candida species", "Pseudomonas aeruginosa", "MRSA"]'::jsonb, 1, 'Candida species are fungal organisms and a recognised cause of ICU-acquired infections, particularly in patients with central lines or broad-spectrum antibiotic exposure.', 'Laboratory Sciences & Haematology', '🔬', true),
(3197, 'Laboratory Sciences (CCN 426)', 'AI Practice Question', 'MRSA stands for and is significant because it is:', '["Methicillin-Resistant Staphylococcus Aureus — a bacterium resistant to many common antibiotics", "A virus with no antibiotic resistance concerns", "A fungal skin infection only", "A type of blood cell disorder"]'::jsonb, 0, 'MRSA (Methicillin-Resistant Staphylococcus Aureus) is a bacterium resistant to many beta-lactam antibiotics, requiring careful infection-control measures and alternative antibiotic choices.', 'Laboratory Sciences & Haematology', '🔬', true),
(3198, 'Laboratory Sciences (CCN 426)', 'AI Practice Question', 'Catheter-associated urinary tract infection (CAUTI) prevention in the ICU relies mainly on:', '["Leaving urinary catheters in place for the entire ICU stay regardless of need", "Using catheters only when clinically indicated, maintaining a closed drainage system, and removing them as soon as possible", "Routinely irrigating catheters with antiseptic solution daily", "Avoiding hand hygiene around the catheter to reduce irritation"]'::jsonb, 1, 'CAUTI prevention bundles emphasise appropriate indication for catheter use, maintaining a closed sterile drainage system, and prompt removal once no longer needed.', 'Laboratory Sciences & Haematology', '🔬', true),
(3199, 'Laboratory Sciences (CCN 426)', 'AI Practice Question', 'A full blood count (FBC) primarily provides information about:', '["Liver enzyme levels only", "Red cells, white cells, and platelets", "Blood clotting time exclusively", "Blood glucose levels"]'::jsonb, 1, 'A full blood count measures red blood cell, white blood cell and platelet parameters, providing a broad picture of haematological status.', 'Laboratory Sciences & Haematology', '🔬', true),
(3200, 'Laboratory Sciences (CCN 426)', 'AI Practice Question', 'A significantly prolonged clotting/bleeding time in a patient with recurrent excessive bleeding after minor trauma is most suggestive of:', '["Iron deficiency anaemia", "A coagulation disorder such as haemophilia or Von Willebrand disease", "Simple dehydration", "Hypertension"]'::jsonb, 1, 'Prolonged bleeding/clotting time with recurrent excessive bleeding points toward an underlying coagulation disorder such as haemophilia or Von Willebrand disease.', 'Laboratory Sciences & Haematology', '🔬', true),
(3201, 'Laboratory Sciences (CCN 426)', 'AI Practice Question', 'Standard precautions (universal precautions) in infection control apply to:', '["Only patients with a confirmed infectious disease diagnosis", "All patients, regardless of known or suspected infection status, since blood and body fluids should always be treated as potentially infectious", "Only healthcare workers who have not been vaccinated", "Only surgical patients"]'::jsonb, 1, 'Standard precautions apply universally to all patients, since infection status is not always known — blood and body fluids are always treated as potentially infectious.', 'Laboratory Sciences & Haematology', '🔬', true),
(3202, 'Laboratory Sciences (CCN 426)', 'AI Practice Question', 'Hand hygiene is considered the single most effective measure to prevent which category of healthcare-associated problem?', '["Medication dosing errors", "Healthcare-associated (nosocomial) infections", "Documentation errors", "Equipment malfunction"]'::jsonb, 1, 'Hand hygiene is widely recognised as the single most effective and cost-efficient measure for preventing healthcare-associated infections.', 'Laboratory Sciences & Haematology', '🔬', true),
(3203, 'Laboratory Sciences (CCN 426)', 'AI Practice Question', 'A patient with tuberculosis being cared for in hospital requires which type of isolation precaution?', '["Contact precautions only", "Airborne precautions, including a negative-pressure room and fit-tested N95 respirator for staff", "No isolation precautions are required", "Droplet precautions using a surgical mask only"]'::jsonb, 1, 'TB is spread via airborne transmission, requiring airborne precautions — a negative-pressure isolation room and properly fit-tested N95 respirators for staff entering the room.', 'Laboratory Sciences & Haematology', '🔬', true),
(3204, 'Laboratory Sciences (CCN 426)', 'AI Practice Question', '''Reverse barrier nursing'' (protective isolation) is used to:', '["Protect staff from an infectious patient", "Protect a severely immunocompromised patient (e.g. on chemotherapy) from acquiring infections from their environment or visitors", "Protect visitors from a contagious patient", "There is no clinical use for this practice"]'::jsonb, 1, 'Reverse barrier nursing protects a vulnerable, immunocompromised patient from external pathogens, rather than protecting others from the patient.', 'Laboratory Sciences & Haematology', '🔬', true),
(3205, 'Laboratory Sciences (CCN 426)', 'AI Practice Question', 'Blood group compatibility testing (crossmatching) before transfusion is essential primarily to prevent:', '["Hypertension", "A potentially fatal haemolytic transfusion reaction from ABO/Rh incompatibility", "Hyperglycaemia", "Wound infection"]'::jsonb, 1, 'Crossmatching confirms ABO/Rh compatibility between donor and recipient blood, preventing potentially fatal acute haemolytic transfusion reactions.', 'Laboratory Sciences & Haematology', '🔬', true),
(3206, 'Laboratory Sciences (CCN 426)', 'AI Practice Question', 'Leukaemia is best broadly described as:', '["A localised skin infection", "A malignant disorder of white blood cell production, leading to abnormal proliferation of immature or dysfunctional leucocytes", "A disorder of platelet shape only", "A disorder exclusively of red blood cells"]'::jsonb, 1, 'Leukaemia is a haematological malignancy characterised by abnormal, uncontrolled proliferation of white blood cells, often crowding out normal blood cell production.', 'Laboratory Sciences & Haematology', '🔬', true),
(3207, 'Laboratory Sciences (CCN 426)', 'AI Practice Question', 'Personal Protective Equipment (PPE) selection for a specific patient encounter should be based primarily on:', '["Staff personal preference only", "The anticipated exposure risk (e.g. mode of transmission, likelihood of body fluid contact) for that specific task/patient", "Availability alone, regardless of the clinical situation", "Hospital policy from an unrelated department"]'::jsonb, 1, 'PPE choice should be risk-based, matched to the anticipated transmission route and exposure risk for the specific patient interaction or procedure being performed.', 'Laboratory Sciences & Haematology', '🔬', true)
